const healthData = $('获取服务状态').first().json;
const articleData = $('获取文章总数').first().json;
const todoData = $('获取待办事项').first().json;

const now = new Date();
const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

// Parse service health
const services = healthData.services || healthData.components || {};
const bellkeeperStatus = (services.bellkeeper?.status === 'healthy' || services.bellkeeper?.status === 'ok' || healthData.status === 'healthy') ? '\u2705' : '\u274c';
const ragflowStatus = (services.ragflow?.status === 'healthy' || services.ragflow?.status === 'ok') ? '\u2705' : '\u274c';
const firecrawlStatus = (services.firecrawl?.status === 'healthy' || services.firecrawl?.status === 'ok') ? '\u2705' : '\u274c';

// Parse article count from pagination
const totalArticles = articleData.pagination?.total || articleData.total || articleData.total_count || 0;

// Parse todos
const memos = todoData.memos || [];
const todoCount = memos.length;

// Build plain text message
const plainMessage = `\ud83d\udcca \u6bcf\u65e5\u77e5\u8bc6\u5e93\u6458\u8981 - ${dateStr}\n\n\ud83d\udce6 \u670d\u52a1\u72b6\u6001\n- Bellkeeper: ${bellkeeperStatus}\n- RagFlow: ${ragflowStatus}\n- Firecrawl: ${firecrawlStatus}\n\n\ud83d\udcda \u77e5\u8bc6\u5e93\u7edf\u8ba1\n- \u6587\u7ae0\u603b\u6570: ${totalArticles}\n\n\ud83d\udcdd \u5f85\u529e\u4e8b\u9879\n- \u672a\u5b8c\u6210: ${todoCount} \u9879`;

// Build HTML message
const htmlMessage = `<h3>\ud83d\udcca \u6bcf\u65e5\u77e5\u8bc6\u5e93\u6458\u8981 - ${dateStr}</h3>` +
  `<h4>\ud83d\udce6 \u670d\u52a1\u72b6\u6001</h4>` +
  `<ul>` +
  `<li>Bellkeeper: ${bellkeeperStatus}</li>` +
  `<li>RagFlow: ${ragflowStatus}</li>` +
  `<li>Firecrawl: ${firecrawlStatus}</li>` +
  `</ul>` +
  `<h4>\ud83d\udcda \u77e5\u8bc6\u5e93\u7edf\u8ba1</h4>` +
  `<ul><li>\u6587\u7ae0\u603b\u6570: ${totalArticles}</li></ul>` +
  `<h4>\ud83d\udcdd \u5f85\u529e\u4e8b\u9879</h4>` +
  `<ul><li>\u672a\u5b8c\u6210: ${todoCount} \u9879</li></ul>`;

return {
  json: {
    room: 'daily',
    message: plainMessage,
    html: htmlMessage
  }
};
